const resp = $.steps.listDataFiles.response || {};
const data = resp.data || resp;
const files = data.files || data.items || [];
const maxFiles = $.input.maxFiles || 3;
const limited = files.slice(0, maxFiles);

const fileList = limited.map(f => ({
  id: f.id || '',
  name: f.name || f.title || 'unknown',
  mimeType: f.mimeType || '',
  modifiedTime: f.modifiedTime || '',
  size: f.size || 0,
  webViewLink: f.webViewLink || ''
}));

return { files: fileList, totalFound: files.length, processing: fileList.length };

const files = $.steps.parseFileList.output.files;
const goal = $.input.transformGoal || 'Summarize the data and identify trends';

let prompt = 'You are a data analysis specialist. You have received metadata about data files from Google Drive. Analyze the file information and provide a structured data processing report.\n\n';
prompt += 'ANALYSIS GOAL: ' + goal + '\n\n';
prompt += 'DATA FILES:\n';
files.forEach((f, i) => {
  prompt += (i + 1) + '. ' + f.name + ' (type: ' + f.mimeType + ', modified: ' + f.modifiedTime + ')\n';
  if (f.webViewLink) prompt += '   Link: ' + f.webViewLink + '\n';
});
prompt += '\nINSTRUCTIONS:\n';
prompt += '- For each file, infer the likely data structure from the filename\n';
prompt += '- Suggest a transformation plan for each file\n';
prompt += '- Provide sample data processing steps\n';
prompt += '- Identify potential issues (missing data, format problems)\n';
prompt += '- Recommend best practices for working with these file types\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "summary": "Overview of data files found",\n';
prompt += '  "files": [\n';
prompt += '    {\n';
prompt += '      "fileName": "name",\n';
prompt += '      "inferredStructure": "columns and data types",\n';
prompt += '      "transformPlan": "suggested transformation steps",\n';
prompt += '      "potentialIssues": ["issue1"],\n';
prompt += '      "recommendations": ["recommendation1"]\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "overallRecommendations": ["cross-file recommendation"],\n';
prompt += '  "processingComplexity": "low/medium/high"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { summary: raw, files: [], overallRecommendations: [], processingComplexity: 'unknown' }; }

const ai = $.steps.parseAI.output;
const stats = $.steps.parseFileList.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Data File Processing Report', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Files Found:*\n' + stats.totalFound },
  { type: 'mrkdwn', text: '*Files Analyzed:*\n' + stats.processing }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Complexity:*\n' + (ai.processingComplexity || 'N/A') },
  { type: 'mrkdwn', text: '*Status:*\n:white_check_mark: Analysis complete' }
] });
blocks.push({ type: 'divider' });

const summaryText = (ai.summary || 'No summary available.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:*\n' + summaryText } });

if (ai.files && ai.files.length > 0) {
  blocks.push({ type: 'divider' });
  ai.files.slice(0, 5).forEach((f, i) => {
    let text = '*' + (i + 1) + '. ' + (f.fileName || 'File') + '*';
    text += '\n:card_index: ' + (f.inferredStructure || 'Unknown structure');
    text += '\n:gear: ' + (f.transformPlan || 'No plan').slice(0, 300);
    if (f.potentialIssues && f.potentialIssues.length > 0) {
      text += '\n:warning: Issues: ' + f.potentialIssues.join(', ');
    }
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 1800) } });
  });
}

if (ai.overallRecommendations && ai.overallRecommendations.length > 0) {
  blocks.push({ type: 'divider' });
  let recText = '*Recommendations:*\n';
  ai.overallRecommendations.slice(0, 4).forEach((r, i) => { recText += (i + 1) + '. ' + r + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: recText.slice(0, 1000) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Google Drive + Claude AI + One CLI' }] });

const fallback = 'Data Report: ' + stats.processing + ' files analyzed - ' + (ai.summary || '').slice(0, 100);
return { blocks, fallback };
